import React ,{useState}from 'react'

const category =[
    {key:1,value:"Vegetables"},
    {key:2,value:"Fruits"},
    {key:3,value:"Spices"},
    {key:4,value:"Snacks & Beverages"},
    {key:5,value:"Dairy"},
]

const brand =[
    {key:1,value:"Vegetables"},
    {key:2,value:"Fruits"},
    {key:3,value:"Spices"},
    {key:4,value:"Snacks & Beverages"},
    {key:5,value:"Dairy"},
]

function UploadProduct() {
    const [title, settitle] = useState("")
    const [desc, setdesc] = useState("")
    const [price, setprice] = useState(0)
    const titlechange =(event)=>{
        settitle(event.currentTarget.value)
    }
    const descchange =(event)=>{
        setdesc(event.currentTarget.value)
    }
    const pricechange =(event)=>{
        setprice(event.currentTarget.value)
    }
    return (
        <div className="container" style={{margin:'2rem auto'}}>
            <div  style={{margin:'2rem auto', textAlign:'center'}}>
                <h2>Upload your Product here</h2>
            </div>

            <form onSubmit>
                {/* Dropzone */}


                {/* title */}
                <label className="my-3">Title</label>
                <input  className="my-1" onChange={titlechange} value={title}/>
                <br />
                <br />
                {/* description */}
                <label  className="my-3">Description</label>
                <textarea  className="my-1" onChange={descchange} value={desc}/>
                <br />
                <br />
                {/* price */}
                <label  className="my-3">Price</label>
                <input  className="my-1"onChange={pricechange} value={price} type="number"/>
                <br />
                <br />
                {/* brand: */}
                <label  className="my-3">Category</label>
                <select  className="my-3">

                    {brand.map(item=>(
                         <option  className="my-1" key={item.key} value={item.key}>{item.value}</option>
                    ))}
                   
                </select>
                <br />
                <br />
                {/* category */}
                <label  className="my-3">Category</label>
                <select  className="my-3">

                    {category.map(item=>(
                         <option  className="my-1" key={item.key} value={item.key}>{item.value}</option>
                    ))}
                   
                </select>
                <br />
                <br />
                {/* countInStock */}
                <label className="my-3">Price</label>
                <input  className="my-1" onChange value type="number"/>
                <br />
                <br />
                {/* submit button */}
                <button className="btn btn-primary my-3" onClick>Submit</button>
            </form>
        </div>
    )
}

export default UploadProduct
